import React, { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);
  const handleClick = () => {
    setCount(count + 1);
  };
  return (
    <div>
      <p>Say: {count}</p>
      <button onClick={handleClick}>Artır</button>
    </div>
  );
}

